import 'package:flutter/material.dart'; import 'package:flutter_riverpod/flutter_riverpod.dart'; import '../../../../app/router/app_router.dart'; import 'package:go_router/go_router.dart'; import '../../../../core/widgets/app_empty_view.dart'; import '../../../../core/widgets/app_loading_view.dart'; import '../../../auth/presentation/providers/auth_providers.dart'; import '../providers/review_providers.dart'; import 'review_card.dart';
class SellerReviewList extends ConsumerWidget{final String sellerId; const SellerReviewList({super.key,required this.sellerId}); @override Widget build(BuildContext context,WidgetRef ref){final async=ref.watch(sellerReviewsProvider(sellerId)); final user=ref.watch(currentUserProvider); return async.when(loading:()=>const AppLoadingView(),error:(e,_)=>AppEmptyView(title:'Error',message:e.toString()),data:(items)=>items.isEmpty?const AppEmptyView(title:'Review မရှိသေးပါ'):ListView.builder(shrinkWrap:true,physics:const NeverScrollableScrollPhysics(),itemCount:items.length,itemBuilder:(_,i){final r=items[i]; return ReviewCard(review:r,canEdit:user?.uid==r.reviewerId,onEdit:()=>context.push(AppRoutes.submitReviewPath(sellerId:r.sellerId,productId:r.productId,reviewId:r.id)),onDelete:()=>ref.read(reviewControllerProvider.notifier).deleteReview(reviewId:r.id,sellerId:r.sellerId,productId:r.productId));}));}}
